def range_summary(nums):
    nums = sorted(list(set(nums)))
    runs, run_start = [], nums[0]
    for num in nums:
        if num == run_start + 1:
            pass
        elif num > run_start + 1:
            runs.append(f'{run_start}-{num - 1}')
            run_start = num
        else:
            runs.append(str(num))
            run_start = num
    if run_start != nums[-1]:
        runs.append(f'{run_start}-{nums[-1]}')
    return ', '.join(runs) or ''
